  1→const { app, BrowserWindow, ipcMain, dialog } = require('electron');
  2→const path = require('path');
  3→const { spawn } = require('child_process');
  4→const fs = require('fs');
  5→const https = require('https');
  6→const http = require('http');
  7→
  8→let mainWindow;
  9→let db = null;
 10→let currentLangGlobal = 'en';
 11→
 12→const BIN_DIR = app.isPackaged
 13→  ? path.join(process.resourcesPath, 'bin')
 14→  : path.join('E:', '视频下载器具', 'bin');
 15→const YTDLP = path.join(BIN_DIR, 'yt-dlp.exe');
 16→const FFMPEG_DIR = BIN_DIR;
 17→const USER_DATA = app.isPackaged ? path.join(app.getPath('userData')) : __dirname;
 18→const DOWNLOADS = path.join(USER_DATA, 'downloads');
 19→const AI_CONFIG_FILE = path.join(USER_DATA, 'ai_config.json');
 20→
 21→// 6家AI预设: 国外3家 + 国内3家
 22→const AI_PROVIDERS = {
 23→  openai:   { name: 'OpenAI',        baseUrl: 'https://api.openai.com/v1',              model: 'gpt-4o-mini' },
 24→  claude:   { name: 'Claude',        baseUrl: 'https://api.anthropic.com/v1',           model: 'claude-sonnet-4-20250514' },
 25→  groq:     { name: 'Groq',          baseUrl: 'https://api.groq.com/openai/v1',         model: 'llama-3.3-70b-versatile' },
 26→  deepseek: { name: 'DeepSeek(深度求索)', baseUrl: 'https://api.deepseek.com/v1',            model: 'deepseek-chat' },
 27→  qwen:     { name: 'Qwen(通义千问)',    baseUrl: 'https://dashscope.aliyuncs.com/compatible-mode/v1', model: 'qwen-plus' },
 28→  zhipu:    { name: 'Zhipu(智谱清言)',   baseUrl: 'https://open.bigmodel.cn/api/paas/v4',  model: 'glm-4-flash' }
 29→};
 30→
 31→function loadAIConfig() {
 32→  try {
 33→    if (fs.existsSync(AI_CONFIG_FILE)) return JSON.parse(fs.readFileSync(AI_CONFIG_FILE, 'utf-8'));
 34→  } catch(e) {}
 35→  return { provider: 'deepseek', apiKey: '', baseUrl: '', model: '' };
 36→}
 37→function saveAIConfig(cfg) { fs.writeFileSync(AI_CONFIG_FILE, JSON.stringify(cfg, null, 2)); }
 38→
 39→// 通用AI调用 (OpenAI兼容格式, Claude单独处理)
 40→function callAI(prompt) {
 41→  return new Promise((resolve) => {
 42→    const cfg = loadAIConfig();
 43→    if (!cfg.apiKey) { resolve(null); return; }
 44→
 45→    const preset = AI_PROVIDERS[cfg.provider] || {};
 46→    const baseUrl = cfg.baseUrl || preset.baseUrl || '';
 47→    const model = cfg.model || preset.model || '';
 48→    if (!baseUrl) { resolve(null); return; }
 49→
 50→    const isClaude = cfg.provider === 'claude';
 51→    const urlObj = new URL(isClaude ? baseUrl + '/messages' : baseUrl + '/chat/completions');
 52→    const isHttps = urlObj.protocol === 'https:';
 53→
 54→    let body, headers;
 55→    if (isClaude) {
 56→      body = JSON.stringify({
 57→        model, max_tokens: 1024,
 58→        messages: [{ role: 'user', content: prompt }]
 59→      });
 60→      headers = {
 61→        'Content-Type': 'application/json',
 62→        'x-api-key': cfg.apiKey,
 63→        'anthropic-version': '2023-06-01'
 64→      };
 65→    } else {
 66→      body = JSON.stringify({
 67→        model, max_tokens: 1024,
 68→        messages: [
 69→          { role: 'system', content: '你是一个专业的多语言词典和语言学习助手。所有释义、翻译、解释必须使用准确的中文。对英语单词，请给出准确的中文对应词义，不要音译。' },
 70→          { role: 'user', content: prompt }
 71→        ]
 72→      });
 73→      headers = {
 74→        'Content-Type': 'application/json',
 75→        'Authorization': 'Bearer ' + cfg.apiKey
 76→      };
 77→    }
 78→
 79→    const opts = {
 80→      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
 81→      path: urlObj.pathname, method: 'POST', headers
 82→    };
 83→
 84→    const client = isHttps ? https : http;
 85→    const req = client.request(opts, (res) => {
 86→      let data = '';
 87→      res.on('data', d => data += d);
 88→      res.on('end', () => {
 89→        try {
 90→          const json = JSON.parse(data);
 91→          if (isClaude) {
 92→            resolve(json.content?.[0]?.text || null);
 93→          } else {
 94→            resolve(json.choices?.[0]?.message?.content || null);
 95→          }
 96→        } catch(e) { resolve(null); }
 97→      });
 98→    });
 99→    req.on('error', () => resolve(null));
100→    req.setTimeout(15000, () => { req.destroy(); resolve(null); });
101→    req.write(body);
102→    req.end();
103→  });
104→}
