123→function initDB() {
124→  const dbPath = path.join(__dirname, 'stardict.db');
125→  if (fs.existsSync(dbPath)) {
126→    try {
127→      const Database = require('better-sqlite3');
128→      db = new Database(dbPath, { readonly: true });
129→      db.pragma('journal_mode = WAL');
130→    } catch (e) { console.error('ECDICT加载失败:', e.message); }
131→  }
132→}
