158→  try {
159→    // 临时保存配置再测试
160→    saveAIConfig(cfg);
161→    const result = await callAI('请回复"连接成功"四个字');
162→    if (result) return { success: true, message: result.slice(0, 100) };
163→    return { success: false, message: 'API 无响应，请检查 Key 和服务商设置' };
164→  } catch(e) { return { success: false, message: e.message }; }
