167→// 下载视频+字幕
168→ipcMain.handle('download-video', async (_, url, lang) => {
169→  const subLang = LANGUAGES[lang]?.sub || 'en';
170→  return new Promise((resolve) => {
171→    const infoArgs = ['--dump-json', '--no-playlist', url];
172→    if (fs.existsSync(path.join(FFMPEG_DIR, 'ffmpeg.exe'))) infoArgs.unshift('--ffmpeg-location', FFMPEG_DIR);
173→    const infoProc = spawn(YTDLP, infoArgs);
174→    let infoOut = '';
175→    infoProc.stdout.on('data', d => infoOut += d);
176→    infoProc.on('close', (code) => {
177→      let title = 'video_' + Date.now();
178→      if (code === 0) { try { title = JSON.parse(infoOut).title || title; } catch(e) {} }
179→      const safeName = title.replace(/[<>:"/\\|?*]/g, '_').substring(0, 60);
180→      const outTemplate = path.join(DOWNLOADS, safeName + '.%(ext)s');
181→      const args = [
182→        '--ffmpeg-location', FFMPEG_DIR,
183→        '-f', 'bestvideo[height<=720]+bestaudio/best[height<=720]/best',
184→        '--merge-output-format', 'mp4',
185→        '--write-sub', '--write-auto-sub', '--sub-lang', subLang,
186→        '--sub-format', 'vtt', '--convert-subs', 'vtt',
187→        '--no-playlist', '-o', outTemplate, url
188→      ];
189→      const proc = spawn(YTDLP, args);
190→      let stderr = '', maxPercent = 0, streamCount = 0;
191→      proc.stdout.on('data', (data) => {
192→        const output = data.toString();
193→        if (output.includes('Destination:')) streamCount++;
194→        const matches = output.match(/(\d+\.?\d*)%/g);
195→        if (matches) {
196→          let percent = parseFloat(matches[matches.length - 1]);
197→          if (streamCount >= 2) percent = 50 + percent / 2;
198→          else if (streamCount === 1) percent = percent / 2;
199→          if (percent > maxPercent) { maxPercent = percent; mainWindow.webContents.send('download-progress', { percent }); }
200→        }
201→        if (output.includes('Merging')) mainWindow.webContents.send('download-progress', { percent: 99 });
202→      });
203→      proc.stderr.on('data', d => stderr += d);
204→      proc.on('close', (code2) => {
205→        if (code2 !== 0) { resolve({ success: false, error: stderr || '下载失败' }); return; }
206→        const videoFile = path.join(DOWNLOADS, safeName + '.mp4');
207→        let subFile = null;
208→        const possibleSubs = [
209→          path.join(DOWNLOADS, safeName + '.' + subLang + '.vtt'),
210→          path.join(DOWNLOADS, safeName + '.vtt'),
211→        ];
212→        try {
213→          for (const f of fs.readdirSync(DOWNLOADS)) {
214→            if (f.startsWith(safeName) && f.endsWith('.vtt')) possibleSubs.push(path.join(DOWNLOADS, f));
215→          }
216→        } catch(e) {}
217→        for (const p of possibleSubs) { if (fs.existsSync(p)) { subFile = p; break; } }
218→        resolve({ success: true, videoPath: fs.existsSync(videoFile) ? videoFile : null, subtitlePath: subFile, title: safeName });
219→      });
220→      proc.on('error', () => resolve({ success: false, error: 'yt-dlp未找到' }));
221→    });
222→  });
223→});
