225→// ECDICT查词
226→ipcMain.handle('lookup-word', (_, word) => {
227→  if (!db) return null;
228→  try {
229→    return db.prepare('SELECT word, phonetic, translation, exchange FROM stardict WHERE word = ? COLLATE NOCASE').get(word.toLowerCase().trim()) || null;
230→  } catch(e) { return null; }
231→});
