233→// 在线翻译
234→ipcMain.handle('translate-word', (_, word, fromLang) => {
235→  return new Promise((resolve) => {
236→    const url = `https://api.mymemory.translated.net/get?q=${encodeURIComponent(word)}&langpair=${fromLang}|zh`;
237→    https.get(url, (res) => {
238→      let data = '';
239→      res.on('data', d => data += d);
240→      res.on('end', () => {
241→        try {
242→          const json = JSON.parse(data);
243→          resolve({
244→            translation: json.responseData?.translatedText || null,
245→            matches: (json.matches || []).slice(0, 3).map(m => ({ segment: m.segment, translation: m.translation }))
246→          });
247→        } catch(e) { resolve(null); }
248→      });
249→    }).on('error', () => resolve(null));
250→  });
251→});
252→
253→// 在线例句 (多语种)
254→ipcMain.handle('fetch-examples', (_, word, lang) => {
255→  if (lang === 'ja') {
256→    // 日语: jisho.org API
257→    return new Promise((resolve) => {
258→      const url = `https://jisho.org/api/v1/search/words?keyword=${encodeURIComponent(word)}`;
259→      https.get(url, (res) => {
260→        let data = '';
261→        res.on('data', d => data += d);
262→        res.on('end', () => {
263→          try {
264→            const json = JSON.parse(data);
265→            const entry = json.data?.[0];
266→            if (!entry) { resolve(null); return; }
267→            const reading = entry.japanese?.[0]?.reading || '';
268→            const definitions = (entry.senses || []).slice(0, 5).map(s => ({
269→              partOfSpeech: (s.parts_of_speech || []).join(', '),
270→              definition: (s.english_definitions || []).join('; ')
271→            }));
272→            resolve({ phonetic: reading, definitions, examples: [] });
273→          } catch(e) { resolve(null); }
274→        });
275→      }).on('error', () => resolve(null));
276→    });
277→  }
278→  // 英语: dictionaryapi.dev
279→  return new Promise((resolve) => {
280→    const apiLang = lang === 'en' || !lang ? 'en' : lang;
281→    const url = `https://api.dictionaryapi.dev/api/v2/entries/${apiLang}/${encodeURIComponent(word)}`;
282→    https.get(url, (res) => {
283→      let data = '';
284→      res.on('data', d => data += d);
285→      res.on('end', () => {
286→        try {
287→          const json = JSON.parse(data);
288→          if (!Array.isArray(json)) { resolve(null); return; }
289→          const entry = json[0], examples = [], definitions = [];
290→          for (const meaning of (entry.meanings || [])) {
291→            for (const def of (meaning.definitions || [])) {
292→              definitions.push({ partOfSpeech: meaning.partOfSpeech, definition: def.definition });
293→              if (def.example) examples.push(def.example);
294→            }
295→          }
296→          resolve({
297→            phonetic: entry.phonetic || '',
298→            audio: entry.phonetics?.find(p => p.audio)?.audio || '',
299→            definitions: definitions.slice(0, 5),
300→            examples: examples.slice(0, 5)
301→          });
302→        } catch(e) { resolve(null); }
303→      });
304→    }).on('error', () => resolve(null));
305→  });
306→});
