357→ipcMain.handle('import-video', async () => {
358→  const result = await dialog.showOpenDialog(mainWindow, {
359→    title: '选择视频文件',
360→    filters: [{ name: '视频文件', extensions: ['mp4', 'mkv', 'avi', 'mov', 'webm', 'wmv'] }],
361→    properties: ['openFile']
362→  });
363→  if (result.canceled || !result.filePaths.length) return null;
364→  const src = result.filePaths[0];
365→  const dest = path.join(DOWNLOADS, path.basename(src));
366→  sendSubtitleStatus('文件导入中...');
367→  if (src !== dest && !fs.existsSync(dest)) fs.copyFileSync(src, dest);
368→  sendSubtitleStatus('字幕文件检测中...');
369→  // 检查同名字幕文件
370→  for (const ext of ['.vtt', '.srt']) {
371→    const subSrc = src.replace(/\.[^.]+$/, ext);
372→    const subDest = path.join(DOWNLOADS, path.basename(subSrc));
373→    if (fs.existsSync(subSrc) && !fs.existsSync(subDest)) fs.copyFileSync(subSrc, subDest);
374→  }
375→  const subFile = ['.vtt', '.srt'].map(e => dest.replace(/\.[^.]+$/, e)).find(f => fs.existsSync(f));
376→  sendSubtitleStatus(subFile ? '已找到字幕文件，加载中...' : '未找到字幕文件，稍后将自动识别');
377→  return { videoPath: dest, subtitlePath: subFile || null, name: path.basename(dest, path.extname(dest)) };
378→});
