380→// 语音识别生成字幕 (调用本地 funasr 服务)
381→const FUNASR_PYTHON = path.join(require('os').homedir(), 'funasr-venv', 'Scripts', 'python.exe');
382→const FUNASR_SERVER = path.join(require('os').homedir(), '.clawdbot', 'skills', 'funasr-transcribe', 'scripts', 'server.py');
383→let funasrProcess = null;
384→
385→function checkFunasr() {
386→  return new Promise((resolve) => {
387→    const req = http.request({ hostname: '127.0.0.1', port: 8765, path: '/health', method: 'GET', timeout: 3000 }, (res) => {
388→      let d = ''; res.on('data', c => d += c);
389→      res.on('end', () => resolve(true));
390→    });
391→    req.on('error', () => resolve(false));
392→    req.on('timeout', () => { req.destroy(); resolve(false); });
393→    req.end();
394→  });
395→}
396→
397→function sendSubtitleStatus(msg) {
398→  if (mainWindow && !mainWindow.isDestroyed()) mainWindow.webContents.send('subtitle-status', msg);
399→}
400→
401→async function ensureFunasr() {
402→  if (await checkFunasr()) return true;
403→  sendSubtitleStatus('正在启动语音识别服务...');
404→  // 启动服务
405→  if (fs.existsSync(FUNASR_PYTHON) && fs.existsSync(FUNASR_SERVER)) {
406→    funasrProcess = spawn(FUNASR_PYTHON, [FUNASR_SERVER], { stdio: 'ignore', detached: true });
407→    funasrProcess.unref();
408→    // 等待服务就绪，最多60秒
409→    for (let i = 0; i < 60; i++) {
410→      await new Promise(r => setTimeout(r, 1000));
411→      if (await checkFunasr()) {
412→        sendSubtitleStatus('语音识别服务已就绪');
413→        return true;
414→      }
415→      sendSubtitleStatus(`正在启动语音识别服务... (${i + 1}s)`);
416→    }
417→  }
418→  sendSubtitleStatus('语音识别服务启动失败');
419→  return false;
420→}
421→
422→function transcribeFile(filePath) {
423→  return new Promise((resolve) => {
424→    const data = JSON.stringify({ file_path: filePath });
425→    const req = http.request({
426→      hostname: '127.0.0.1', port: 8765, path: '/transcribe',
427→      method: 'POST', headers: { 'Content-Type': 'application/json' }
428→    }, (res) => {
429→      let body = '';
430→      res.on('data', d => body += d);
431→      res.on('end', () => {
432→        try { resolve(JSON.parse(body)); } catch(e) { resolve(null); }
433→      });
434→    });
435→    req.on('error', () => resolve(null));
436→    req.setTimeout(600000, () => { req.destroy(); resolve(null); });
437→    req.write(data);
438→    req.end();
439→  });
440→}
441→
442→const SEGMENT_DURATION = 600; // 10分钟一段
443→
444→ipcMain.handle('generate-subtitle', async (_, videoPath) => {
445→  const ready = await ensureFunasr();
446→  if (!ready) return null;
447→
448→  sendSubtitleStatus('正在分析视频...');
449→  const ffprobe = path.join(FFMPEG_DIR, 'ffprobe.exe');
450→  const ffmpeg = path.join(FFMPEG_DIR, 'ffmpeg.exe');
451→
452→  const duration = await new Promise((resolve) => {
453→    const p = spawn(ffprobe, ['-v', 'quiet', '-print_format', 'json', '-show_format', videoPath]);
454→    let out = '';
455→    p.stdout.on('data', d => out += d);
456→    p.on('close', () => {
457→      try { resolve(parseFloat(JSON.parse(out).format.duration) || 0); } catch(e) { resolve(0); }
458→    });
459→    p.on('error', () => resolve(0));
460→  });
461→  if (!duration) return null;
462→
463→  const durationMin = Math.ceil(duration / 60);
464→  const segCount = Math.ceil(duration / SEGMENT_DURATION);
465→  const tmpDir = path.join(DOWNLOADS, '_tmp_segments');
466→  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
467→
468→  let allText = '';
469→  let vtt = 'WEBVTT\n\n';
470→
471→  for (let i = 0; i < segCount; i++) {
472→    const startSec = i * SEGMENT_DURATION;
473→    const segFile = path.join(tmpDir, `seg_${i}.wav`);
474→
475→    sendSubtitleStatus(`正在提取音频片段 ${i + 1}/${segCount}（视频 ${durationMin} 分钟）`);
476→    const extractOk = await new Promise((resolve) => {
477→      const p = spawn(ffmpeg, ['-y', '-ss', String(startSec), '-t', String(SEGMENT_DURATION), '-i', videoPath, '-vn', '-ar', '16000', '-ac', '1', '-f', 'wav', segFile]);
478→      p.on('close', code => resolve(code === 0));
479→      p.on('error', () => resolve(false));
480→    });
481→    if (!extractOk) continue;
482→
483→    sendSubtitleStatus(`正在转录片段 ${i + 1}/${segCount}（视频 ${durationMin} 分钟）`);
484→
485→    // 确保服务还在（可能被上一段OOM杀了）
486→    const ok = await ensureFunasr();
487→    if (!ok) { try { fs.unlinkSync(segFile); } catch(e) {} continue; }
488→
489→    const result = await transcribeFile(segFile);
490→    try { fs.unlinkSync(segFile); } catch(e) {}
491→
492→    if (!result || !result.success || !result.text) continue;
493→
494→    // 使用 funasr 返回的真实时间戳
495→    const text = result.text;
496→    const timestamps = result.timestamp || [];
497→
498→    if (timestamps.length > 0) {
499→      // 按标点分句，用时间戳精确定位每句的起止时间
500→      const noSpace = text.replace(/\s/g, '');
501→      const sentenceEnds = /[.!?。！？]/g;
502→      // 在原文中按标点分句，保留空格
503→      let sentences = [];
504→      let lastPos = 0;
505→      let charCount = 0;
506→      for (let i = 0; i < text.length; i++) {
507→        if (/\s/.test(text[i])) continue;
508→        charCount++;
509→        if (/[.!?。！？]/.test(text[i])) {
510→          const s = text.slice(lastPos, i + 1).trim();
511→          const charEnd = charCount;
512→          const charStart = charEnd - s.replace(/\s/g, '').length;
513→          if (s) sentences.push({ text: s, charStart, charEnd });
514→          lastPos = i + 1;
515→        }
516→      }
517→      if (lastPos < text.length) {
518→        const s = text.slice(lastPos).trim();
519→        if (s) sentences.push({ text: s, charStart: charCount - s.replace(/\s/g, '').length, charEnd: charCount });
520→      }
521→      if (!sentences.length) sentences.push({ text, charStart: 0, charEnd: noSpace.length });
522→
523→      const totalChars = noSpace.length;
524→      const totalTs = timestamps.length;
525→
526→      for (const sent of sentences) {
527→        const tsStart = Math.floor(sent.charStart / totalChars * totalTs);
528→        const tsEnd = Math.min(Math.floor(sent.charEnd / totalChars * totalTs), totalTs - 1);
529→        const startMs = timestamps[tsStart] ? timestamps[tsStart][0] : 0;
530→        const endMs = timestamps[tsEnd] ? timestamps[tsEnd][1] : startMs + 1000;
531→        const start = fmtVTT(startSec + startMs / 1000);
532→        const end = fmtVTT(startSec + endMs / 1000);
533→        vtt += `${start} --> ${end}\n${sent.text}\n\n`;
534→      }
535→    } else {
536→      // 无时间戳回退：按文本长度估算
537→      const sentences = (text.match(/[^.!?。！？]+[.!?。！？]+/g) || [text]).map(s => s.trim()).filter(s => s.length > 0);
538→      if (!sentences.length) { allText += text; continue; }
539→      const segDur = Math.min(SEGMENT_DURATION, duration - startSec);
540→      const totalLen = sentences.reduce((a, s) => a + s.length, 0);
541→      let t = startSec;
542→      for (const s of sentences) {
543→        const seg = (s.length / totalLen) * segDur;
544→        const start = fmtVTT(t);
545→        t += seg;
546→        const end = fmtVTT(t);
547→        vtt += `${start} --> ${end}\n${s}\n\n`;
548→      }
549→    }
550→    allText += text;
551→  }
552→
553→  // 清理临时目录
554→  try { fs.rmSync(tmpDir, { recursive: true }); } catch(e) {}
555→
556→  if (!allText) { sendSubtitleStatus('语音识别失败'); return null; }
557→
558→  const vttPath = videoPath.replace(/\.[^.]+$/, '.vtt');
559→  fs.writeFileSync(vttPath, vtt, 'utf-8');
560→  sendSubtitleStatus(`转录完成，共 ${segCount} 段`);
561→  return vttPath;
562→});
563→
564→function fmtVTT(sec) {
565→  const h = Math.floor(sec / 3600), m = Math.floor((sec % 3600) / 60), s = sec % 60;
566→  return String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ':' + s.toFixed(3).padStart(6,'0');
567→}
