.vocab-card:hover .vocab-card-del { display: block; }
```

#### renderer.js additions (~60 lines)

```javascript
// DOM refs
const vocabBtn = document.getElementById('vocabBtn');
const vocabModal = document.getElementById('vocabModal');
const vocabModalClose = document.getElementById('vocabModalClose');
const vocabGrid = document.getElementById('vocabGrid');
const vocabEmpty = document.getElementById('vocabEmpty');
const popupFavBtn = document.getElementById('popupFavBtn');
const inlineFavBtn = document.getElementById('inlineFavBtn');

// Toggle vocab modal
vocabBtn.addEventListener('click', () => { vocabModal.classList.add('show'); loadVocabList(); });
vocabModalClose.addEventListener('click', () => vocabModal.classList.remove('show'));
vocabModal.addEventListener('click', e => { if (e.target === vocabModal) vocabModal.classList.remove('show'); });

// Add/remove favorite from popup
popupFavBtn.addEventListener('click', async () => {
  const word = popupWord.textContent;
  if (!word) return;
  const isFaved = await ipcRenderer.invoke('fav-check', word, currentLang);
  if (isFaved) {
    await ipcRenderer.invoke('fav-remove', word, currentLang);
    popupFavBtn.textContent = '☆ 收藏'; popupFavBtn.classList.remove('faved');
  } else {
    await ipcRenderer.invoke('fav-add', word, currentLang, popupPhonetic.textContent, popupTranslation.textContent, currentSentence);
    popupFavBtn.textContent = '★ 已收藏'; popupFavBtn.classList.add('faved');
  }
});

// Same for inline panel
inlineFavBtn.addEventListener('click', async () => {
  const word = inlineWord.textContent;
  if (!word) return;
  const isFaved = await ipcRenderer.invoke('fav-check', word, currentLang);
  if (isFaved) {
    await ipcRenderer.invoke('fav-remove', word, currentLang);
    inlineFavBtn.textContent = '☆ 收藏'; inlineFavBtn.classList.remove('faved');
  } else {
    await ipcRenderer.invoke('fav-add', word, currentLang, inlinePhonetic.textContent, inlineTranslation.textContent, currentSentence);
    inlineFavBtn.textContent = '★ 已收藏'; inlineFavBtn.classList.add('faved');
  }
});

// Update fav button state when showing word popup/inline
// Add to end of showWordPopup: check fav state
// Add to end of showWordInline: check fav state
async function updateFavState(word) {
  const faved = await ipcRenderer.invoke('fav-check', word, currentLang);
  popupFavBtn.textContent = faved ? '★ 已收藏' : '☆ 收藏';
  popupFavBtn.classList.toggle('faved', faved);
  inlineFavBtn.textContent = faved ? '★ 已收藏' : '☆ 收藏';
  inlineFavBtn.classList.toggle('faved', faved);
}

// Load vocab list into grid
async function loadVocabList() {
  const list = await ipcRenderer.invoke('fav-list');
  vocabGrid.innerHTML = '';
  vocabEmpty.style.display = list.length ? 'none' : 'block';
  for (const item of list) {
    const card = document.createElement('div');
    card.className = 'vocab-card';
    card.innerHTML = `
      <div class="vocab-card-word">${item.word}</div>
      <div class="vocab-card-phonetic">${item.phonetic || ''}</div>
      <div class="vocab-card-trans">${item.translation || ''}</div>
      <button class="vocab-card-del" data-word="${item.word}" data-lang="${item.lang}">✕</button>`;
    card.querySelector('.vocab-card-del').addEventListener('click', async (e) => {
      e.stopPropagation();
      await ipcRenderer.invoke('fav-remove', item.word, item.lang);
      loadVocabList();
    });
    card.addEventListener('click', () => speak(item.word, languages[item.lang]?.tts));
    vocabGrid.appendChild(card);
  }
}

// Hook into existing showWordPopup and showWordInline -- add updateFavState(word) call at end of each
```

Modification points in existing code:
- At the end of `showWordPopup()` function (~line 557 in renderer.js): add `updateFavState(word);`
- At the end of `showWordInline()` function (~line 504 in renderer.js): add `updateFavState(word);`

