imgModal.addEventListener('click', e => { if (e.target === imgModal) imgModal.classList.remove('show'); });

// Import words button in vocab modal
document.getElementById('vocabImportBtn').addEventListener('click', async () => {
  const text = await navigator.clipboard.readText();
  if (!text) return;
  const words = text.split(/[\n,;，；\s]+/).map(w => w.trim()).filter(Boolean);
  if (!words.length) return;
  const count = await ipcRenderer.invoke('fav-import', words, currentLang);
  loadVocabList();
});

// Export images button
document.getElementById('vocabExportImgBtn').addEventListener('click', async () => {
  const list = await ipcRenderer.invoke('fav-list');
  if (!list.length) return;
  imgModal.classList.add('show');
  imgPreview.innerHTML = '';
  imgStatus.textContent = 'AI正在分组...';
  imgStatus.style.display = 'block';

  const words = list.map(w => w.word);
  const groups = await ipcRenderer.invoke('ai-group-words', words);

  imgStatus.textContent = '正在生成图片...';
  for (let i = 0; i < groups.length; i++) {
    const group = groups[i];
    const groupItems = list.filter(w => group.includes(w.word));
    const sceneDesc = await ipcRenderer.invoke('ai-scene-desc', group);
    const dataUrl = renderWordGroupImage(groupItems, sceneDesc, i);
    const div = document.createElement('div');
    div.className = 'img-card';
    const img = document.createElement('img');
    img.src = dataUrl;
    img.addEventListener('click', () => {
      const a = document.createElement('a');
      a.href = dataUrl; a.download = `words_group_${i + 1}.png`; a.click();
    });
    div.appendChild(img);
    imgPreview.appendChild(div);
  }
  imgStatus.style.display = 'none';
});

// Canvas rendering
function renderWordGroupImage(items, sceneDesc, groupIdx) {
  const canvas = wordCanvas;
  const cols = Math.ceil(Math.sqrt(items.length));
  const rows = Math.ceil(items.length / cols);
  const cellW = 220, cellH = 120, pad = 40;
  canvas.width = cols * cellW + pad * 2;
  canvas.height = rows * cellH + pad * 2 + 60;
  const ctx = canvas.getContext('2d');

  // Background gradient
  const grad = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
  const palettes = [['#1a0a2e','#0a1a2e'],['#0a2e1a','#1a2e0a'],['#2e0a1a','#2e1a0a']];
  const pal = palettes[groupIdx % palettes.length];
  grad.addColorStop(0, pal[0]); grad.addColorStop(1, pal[1]);
  ctx.fillStyle = grad; ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Scene description at top
  ctx.fillStyle = 'rgba(255,255,255,0.4)'; ctx.font = '14px sans-serif'; ctx.textAlign = 'center';
  ctx.fillText(sceneDesc || '', canvas.width / 2, 30);

  // Word cards
  items.forEach((item, i) => {
    const col = i % cols, row = Math.floor(i / cols);
    const x = pad + col * cellW, y = 50 + row * cellH;
    // Card bg
    ctx.fillStyle = 'rgba(255,255,255,0.08)';
    ctx.beginPath(); ctx.roundRect(x + 4, y + 4, cellW - 8, cellH - 8, 10); ctx.fill();
    // Word
    ctx.fillStyle = '#ff6b9d'; ctx.font = 'bold 20px sans-serif'; ctx.textAlign = 'center';
    ctx.fillText(item.word, x + cellW / 2, y + 38);
    // Phonetic
    ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.font = '12px sans-serif';
    ctx.fillText(item.phonetic || '', x + cellW / 2, y + 56);
    // Translation (truncate)
    ctx.fillStyle = '#fff'; ctx.font = '14px sans-serif';
    const trans = (item.translation || '').slice(0, 20);
    ctx.fillText(trans, x + cellW / 2, y + 80);
  });

  return canvas.toDataURL('image/png');
}
