```javascript
const assistantBtn = document.getElementById('assistantBtn');
const assistantModal = document.getElementById('assistantModal');
const assistantModalClose = document.getElementById('assistantModalClose');
const assistantText = document.getElementById('assistantText');
const assistantPlayBtn = document.getElementById('assistantPlayBtn');
const assistantStopBtn = document.getElementById('assistantStopBtn');
const assistantStatus = document.getElementById('assistantStatus');

let lectureParagraphs = [];
let lectureIndex = 0;
let lecturing = false;

assistantBtn.addEventListener('click', () => assistantModal.classList.add('show'));
assistantModalClose.addEventListener('click', () => { assistantModal.classList.remove('show'); speechSynthesis.cancel(); lecturing = false; });
assistantModal.addEventListener('click', e => { if (e.target === assistantModal) assistantModal.classList.remove('show'); });

document.getElementById('assistantUploadBtn').addEventListener('click', async () => {
  const text = await ipcRenderer.invoke('read-file-text');
  if (!text) return;
  assistantStatus.textContent = 'AI正在整理讲稿...';
  assistantText.style.display = 'block';
  assistantText.textContent = '处理中...';
  const lecture = await ipcRenderer.invoke('ai-lecture', text);
  if (!lecture) { assistantStatus.textContent = 'AI处理失败'; return; }
  assistantText.textContent = lecture;
  lectureParagraphs = lecture.split(/\n+/).filter(p => p.trim());
  assistantPlayBtn.style.display = 'block';
  assistantStopBtn.style.display = 'block';
  assistantStatus.textContent = `讲稿就绪，共 ${lectureParagraphs.length} 段`;
});

assistantPlayBtn.addEventListener('click', () => {
  if (!lectureParagraphs.length) return;
  lecturing = true; lectureIndex = 0;
  speakLecture();
});

assistantStopBtn.addEventListener('click', () => {
  lecturing = false; speechSynthesis.cancel();
  assistantStatus.textContent = '已停止';
});

function speakLecture() {
  if (!lecturing || lectureIndex >= lectureParagraphs.length) {
    lecturing = false; assistantStatus.textContent = '朗读完毕'; return;
  }
  assistantStatus.textContent = `正在朗读第 ${lectureIndex + 1}/${lectureParagraphs.length} 段`;
  const u = new SpeechSynthesisUtterance(lectureParagraphs[lectureIndex]);
  u.lang = 'zh-CN'; u.rate = 0.9;
  u.onend = () => { lectureIndex++; if (lecturing) setTimeout(speakLecture, 500); };
  speechSynthesis.speak(u);
}
```

